/**
 * API Documentation Generator
 *
 * Pure functions engine to parse Next.js App Router route files
 * and generate OpenAPI 3.0 specification.
 *
 * Design: zero I/O, zero side-effects. Every function receives data
 * as arguments and returns a deterministic result.
 */

// === TYPES ===

export type HttpMethod = 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE' | 'HEAD' | 'OPTIONS';

export interface RouteInfo {
  /** e.g. "src/app/api/auth/login/route.ts" */
  filePath: string;
  /** e.g. "/api/auth/login" */
  apiPath: string;
  /** e.g. ['POST'] */
  methods: HttpMethod[];
  /** e.g. "auth" */
  domain: string;
  hasDynamicSegments: boolean;
  /** e.g. ['id'] from [id]/route.ts */
  dynamicParams: string[];
}

export interface ApiDomain {
  name: string;
  description: string;
  routes: RouteInfo[];
  routeCount: number;
}

export interface OpenApiSpec {
  openapi: string;
  info: OpenApiInfo;
  servers: OpenApiServer[];
  paths: Record<string, OpenApiPathItem>;
  tags: OpenApiTag[];
}

export interface OpenApiInfo {
  title: string;
  description: string;
  version: string;
  contact?: { name: string; url?: string; email?: string };
}

export interface OpenApiServer {
  url: string;
  description: string;
}

export interface OpenApiPathItem {
  [method: string]: OpenApiOperation;
}

export interface OpenApiOperation {
  tags: string[];
  summary: string;
  operationId: string;
  parameters?: OpenApiParameter[];
  responses: Record<string, OpenApiResponse>;
}

export interface OpenApiParameter {
  name: string;
  in: 'path' | 'query' | 'header';
  required: boolean;
  schema: { type: string };
  description?: string;
}

export interface OpenApiResponse {
  description: string;
  content?: Record<string, { schema: { type: string } }>;
}

export interface OpenApiTag {
  name: string;
  description: string;
}

export interface GeneratorConfig {
  title?: string;
  description?: string;
  version?: string;
  serverUrl?: string;
  contactName?: string;
  contactUrl?: string;
}

export interface GeneratorSummary {
  totalRoutes: number;
  /** routes × methods */
  totalEndpoints: number;
  domains: string[];
  methodBreakdown: Record<HttpMethod, number>;
  dynamicRoutes: number;
  staticRoutes: number;
}

