// === PURE FUNCTIONS ===

/**
 * Converts a file path to an API path.
 * "src/app/api/auth/login/route.ts" → "/api/auth/login"
 * Dynamic segments are converted: [id] → {id}
 */
export function filePathToApiPath(filePath: string): string {
  // Normalise separators to forward-slash
  const normalised = filePath.replace(/\\/g, '/');

  // Find the /api/ segment and strip everything before `app/`
  const appIdx = normalised.indexOf('app/api/');
  if (appIdx === -1) {
    // Fallback: return the whole path minus route.ts for malformed inputs
    return '/' + normalised.replace(/\/route\.(ts|js)$/, '');
  }

  // Get the part after "app/"
  let apiSegment = normalised.slice(appIdx + 'app'.length);

  // Remove trailing /route.ts or /route.js
  apiSegment = apiSegment.replace(/\/route\.(ts|js)$/, '');

  // Convert Next.js dynamic segments [param] → {param}
  apiSegment = apiSegment.replace(/\[([^\]]+)\]/g, '{$1}');

  // Ensure leading slash
  if (!apiSegment.startsWith('/')) {
    apiSegment = '/' + apiSegment;
  }

  return apiSegment;
}

/**
 * Extracts dynamic parameter names from an API path.
 * "/api/users/{id}/posts/{postId}" → ["id", "postId"]
 */
export function extractDynamicParams(apiPath: string): string[] {
  const params: string[] = [];
  const regex = /\{([^}]+)\}/g;
  let match: RegExpExecArray | null = regex.exec(apiPath);
  while (match !== null) {
    params.push(match[1]);
    match = regex.exec(apiPath);
  }
  return params;
}

/**
 * Extracts the first segment after /api/ as the domain name.
 * "/api/auth/login" → "auth"
 * "/api/v2/render"  → "v2"
 */
export function extractDomain(apiPath: string): string {
  // Remove leading slash and split
  const segments = apiPath.replace(/^\//, '').split('/');
  // segments: ["api", "auth", "login"]
  const apiIdx = segments.indexOf('api');
  if (apiIdx === -1 || apiIdx + 1 >= segments.length) {
    return 'unknown';
  }
  const domain = segments[apiIdx + 1];
  // Strip OpenAPI param braces to avoid {id} as domain
  return domain.replace(/[{}]/g, '') || 'unknown';
}

/**
 * Scans file content for exported HTTP method handlers.
 *
 * Recognises patterns:
 *   export async function GET(...)
 *   export function POST(...)
 *   export const PUT = ...
 *   export { GET, POST }
 *   export { GET as default, POST }
 */
export function parseRouteExports(fileContent: string): HttpMethod[] {
  const found = new Set<HttpMethod>();

  for (const method of VALID_HTTP_METHODS) {
    // Pattern 1: export async function METHOD  /  export function METHOD
    const fnPattern = new RegExp(
      `export\\s+(?:async\\s+)?function\\s+${method}\\b`,
    );
    if (fnPattern.test(fileContent)) {
      found.add(method);
      continue;
    }

    // Pattern 2: export const METHOD  /  export let METHOD
    const constPattern = new RegExp(
      `export\\s+(?:const|let|var)\\s+${method}\\b`,
    );
    if (constPattern.test(fileContent)) {
      found.add(method);
      continue;
    }

    // Pattern 3: export { ..., METHOD, ... }
    // Match across potential multi-line export statements
    const namedExportPattern = new RegExp(
      `export\\s*\\{[^}]*\\b${method}\\b[^}]*\\}`,
      's',
    );
    if (namedExportPattern.test(fileContent)) {
      found.add(method);
    }
  }

  return VALID_HTTP_METHODS.filter((m) => found.has(m));
}

/**
 * Builds a complete RouteInfo from file path and content.
 */
export function buildRouteInfo(filePath: string, fileContent: string): RouteInfo {
  const apiPath = filePathToApiPath(filePath);
  const methods = parseRouteExports(fileContent);
  const domain = extractDomain(apiPath);
  const dynamicParams = extractDynamicParams(apiPath);
  const hasDynamicSegments = dynamicParams.length > 0;

  return {
    filePath,
    apiPath,
    methods,
    domain,
    hasDynamicSegments,
    dynamicParams,
  };
}

/**
 * Groups routes by domain, sorted alphabetically.
 * Unknown domains receive a generic description.
 */
export function groupByDomain(routes: RouteInfo[]): ApiDomain[] {
  const domainMap = new Map<string, RouteInfo[]>();

  for (const route of routes) {
    const existing = domainMap.get(route.domain);
    if (existing) {
      existing.push(route);
    } else {
      domainMap.set(route.domain, [route]);
    }
  }

  const domains: ApiDomain[] = [];
  const sortedKeys = Array.from(domainMap.keys()).sort();

  for (const key of sortedKeys) {
    const domainRoutes = domainMap.get(key) ?? [];
    domains.push({
      name: key,
      description:
        API_DOMAINS[key] ?? `${key.charAt(0).toUpperCase() + key.slice(1)} endpoints`,
      routes: domainRoutes,
      routeCount: domainRoutes.length,
    });
  }

  return domains;
}

/**
 * Creates a unique operation ID from method + path.
 * GET /api/auth/login     → "getAuthLogin"
 * POST /api/users/{id}    → "postUsersById"
 */
export function generateOperationId(method: HttpMethod, apiPath: string): string {
  const lower = method.toLowerCase();

  // Remove /api/ prefix and split
  const cleaned = apiPath
    .replace(/^\/api\//, '')
    .replace(/\{([^}]+)\}/g, (_match, param: string) => {
      // {id} → ById, {postId} → ByPostId
      return 'By' + param.charAt(0).toUpperCase() + param.slice(1);
    });

  const parts = cleaned.split('/').filter(Boolean);

  // CamelCase join
  const suffix = parts
    .map((p) => p.charAt(0).toUpperCase() + p.slice(1))
    .join('');

  return lower + suffix;
}

/**
 * Creates OpenAPI parameter objects for dynamic segments in a route.
 */
export function buildPathParameters(route: RouteInfo): OpenApiParameter[] {
  return route.dynamicParams.map((param) => ({
    name: param,
    in: 'path' as const,
    required: true,
    schema: { type: 'string' },
    description: `The ${param} parameter`,
  }));
}

/**
 * Builds an OpenAPI PathItem with one operation per HTTP method.
 */
export function buildPathItem(route: RouteInfo): OpenApiPathItem {
  const params = buildPathParameters(route);
  const item: OpenApiPathItem = {};

  for (const method of route.methods) {
    const operation: OpenApiOperation = {
      tags: [route.domain],
      summary: `${method} ${route.apiPath}`,
      operationId: generateOperationId(method, route.apiPath),
      responses: {
        '200': {
          description: 'Successful response',
          content: {
            'application/json': {
              schema: { type: 'object' },
            },
          },
        },
        '400': { description: 'Bad request' },
        '401': { description: 'Unauthorized' },
        '500': { description: 'Internal server error' },
      },
    };

    if (params.length > 0) {
      operation.parameters = params;
    }

    item[method.toLowerCase()] = operation;
  }

  return item;
}

/**
 * Creates OpenAPI tag list from domain groups.
 */
export function buildTags(domains: ApiDomain[]): OpenApiTag[] {
  return domains.map((d) => ({
    name: d.name,
    description: d.description,
  }));
}

/**
 * Main entry-point: builds a complete OpenAPI 3.0.3 specification
 * from an array of RouteInfo objects.
 */
export function generateOpenApiSpec(
  routes: RouteInfo[],
  config?: GeneratorConfig,
): OpenApiSpec {
  const merged: Required<GeneratorConfig> = { ...DEFAULT_CONFIG, ...config };
  const domains = groupByDomain(routes);

  const paths: Record<string, OpenApiPathItem> = {};
  for (const route of routes) {
    paths[route.apiPath] = buildPathItem(route);
  }

  return {
    openapi: '3.0.3',
    info: {
      title: merged.title,
      description: merged.description,
      version: merged.version,
      contact: {
        name: merged.contactName,
        url: merged.contactUrl,
      },
    },
    servers: [
      {
        url: merged.serverUrl,
        description: 'Primary server',
      },
    ],
    paths,
    tags: buildTags(domains),
  };
}

/**
 * Computes summary statistics for a set of routes.
 */
export function generateSummary(routes: RouteInfo[]): GeneratorSummary {
  const methodBreakdown: Record<HttpMethod, number> = {
    GET: 0,
    POST: 0,
    PUT: 0,
    PATCH: 0,
    DELETE: 0,
    HEAD: 0,
    OPTIONS: 0,
  };

  let totalEndpoints = 0;
  let dynamicRoutes = 0;
  let staticRoutes = 0;
  const domainSet = new Set<string>();

  for (const route of routes) {
    for (const method of route.methods) {
      methodBreakdown[method]++;
      totalEndpoints++;
    }
    if (route.hasDynamicSegments) {
      dynamicRoutes++;
    } else {
      staticRoutes++;
    }
    domainSet.add(route.domain);
  }

  return {
    totalRoutes: routes.length,
    totalEndpoints,
    domains: Array.from(domainSet).sort(),
    methodBreakdown,
    dynamicRoutes,
    staticRoutes,
  };
}

/**
 * Serialises an OpenAPI spec to JSON.
 * @param pretty — when true uses 2-space indentation (default true)
 */
export function formatSpecAsJson(spec: OpenApiSpec, pretty = true): string {
  return pretty
    ? JSON.stringify(spec, null, 2)
    : JSON.stringify(spec);
}

/**
 * Basic structural validation of an OpenAPI spec object.
 * Returns { valid, errors } — this is NOT a full OpenAPI schema validator,
 * but catches the most common structural mistakes.
 */
export function validateSpec(
  spec: OpenApiSpec,
): { valid: boolean; errors: string[] } {
  const errors: string[] = [];

  // 1. Required top-level fields
  if (!spec.openapi) {
    errors.push('Missing required field: openapi');
  } else if (!spec.openapi.startsWith('3.')) {
    errors.push(`Invalid openapi version: ${spec.openapi}`);
  }

  if (!spec.info) {
    errors.push('Missing required field: info');
  } else {
    if (!spec.info.title) errors.push('Missing required field: info.title');
    if (!spec.info.version) errors.push('Missing required field: info.version');
  }

  // 2. Paths must exist and not be empty
  if (!spec.paths) {
    errors.push('Missing required field: paths');
  } else if (Object.keys(spec.paths).length === 0) {
    errors.push('Paths object is empty');
  } else {
    // 3. Each path must have at least one valid method
    for (const [path, pathItem] of Object.entries(spec.paths)) {
      const methods = Object.keys(pathItem);
      if (methods.length === 0) {
        errors.push(`Path "${path}" has no operations`);
        continue;
      }

      const validLower = VALID_HTTP_METHODS.map((m) => m.toLowerCase());
      for (const m of methods) {
        if (!validLower.includes(m as Lowercase<HttpMethod>)) {
          errors.push(`Path "${path}" has invalid method: ${m}`);
        }
      }
    }
  }

  // 4. Tags should be an array
  if (spec.tags && !Array.isArray(spec.tags)) {
    errors.push('Tags must be an array');
  }

  return { valid: errors.length === 0, errors };
}
